mapper.select:
SELECT COUNT(*) > 0
FROM recruitment_application_portfolio_snapshot_file sf
INNER JOIN recruitment_application_portfolio_snapshot ps
    ON ps.snapshot_id = sf.snapshot_id
WHERE ps.application_id = #{applicationId}
  AND ps.portfolio_id = #{portfolioId}
  AND sf.file_id = #{fileId}

SELECT (
    EXISTS (
        SELECT 1
        FROM recruitment_application_portfolio_snapshot_file sf
        WHERE sf.file_id = #{fileId}
    )
    OR EXISTS (
        SELECT 1
        FROM recruitment_application_portfolio_snapshot ps
        WHERE ps.banner_file_id = #{fileId}
    )
)
